:root {
  --font-sans: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Open Sans', 'Helvetica Neue', sans-serif;
  --bg-primary: #f8fafc;
  --bg-card: #ffffff;
  --text-primary: #0f172a;
  --text-secondary: #475569;
  --text-muted: #94a3b8;
  --primary: #4f46e5;
  --primary-hover: #4338ca;
  --primary-light: #e0e7ff;
  --danger: #ef4444;
  --danger-hover: #dc2626;
  --border: #e2e8f0;
  --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);
  --radius: 12px;
  --radius-sm: 8px;
}

body {
  margin: 0;
  font-family: var(--font-sans);
  background-color: var(--bg-primary);
  color: var(--text-primary);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

#root {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

* {
  box-sizing: border-box;
}

/* Layout */
.app-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 24px;
  width: 100%;
}

.header {
  background-color: var(--bg-card);
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 0;
  z-index: 50;
  box-shadow: var(--shadow-sm);
}

.header-content {
  max-width: 1200px;
  margin: 0 auto;
  padding: 16px 24px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.logo {
  font-size: 24px;
  font-weight: 800;
  color: var(--primary);
  text-decoration: none;
  display: flex;
  align-items: center;
  gap: 8px;
}

.logo-icon {
  width: 32px;
  height: 32px;
}

.main-layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 32px;
  margin-top: 24px;
}

@media (min-width: 1024px) {
  .main-layout {
    grid-template-columns: 2fr 1fr;
  }
}

/* Products Section */
.products-section {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.section-title {
  font-size: 20px;
  font-weight: 700;
  margin: 0;
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--text-primary);
}

.products-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 20px;
}

@media (min-width: 640px) {
  .products-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

/* Product Card */
.product-card {
  background-color: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
  box-shadow: var(--shadow-sm);
  transition: transform 0.2s, box-shadow 0.2s;
  display: flex;
  flex-direction: column;
}

.product-card:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-md);
}

.product-image-container {
  position: relative;
  width: 100%;
  padding-top: 66%; /* 3:2 Aspect Ratio */
  background-color: #f1f5f9;
}

.product-image {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.product-category {
  position: absolute;
  top: 12px;
  left: 12px;
  background-color: rgba(255, 255, 255, 0.9);
  color: var(--text-secondary);
  font-size: 11px;
  font-weight: 600;
  padding: 4px 8px;
  border-radius: 20px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  box-shadow: var(--shadow-sm);
}

.product-info {
  padding: 16px;
  display: flex;
  flex-direction: column;
  flex-grow: 1;
}

.product-name {
  font-size: 16px;
  font-weight: 600;
  margin: 0 0 8px 0;
  color: var(--text-primary);
  line-height: 1.4;
}

.product-desc {
  font-size: 13px;
  color: var(--text-secondary);
  margin: 0 0 16px 0;
  line-height: 1.5;
  flex-grow: 1;
}

.product-footer {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: auto;
}

.product-price {
  font-size: 20px;
  font-weight: 700;
  color: var(--primary);
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 10px 16px;
  font-size: 14px;
  font-weight: 600;
  border-radius: var(--radius-sm);
  border: none;
  cursor: pointer;
  transition: background-color 0.15s, color 0.15s;
}

.btn-primary {
  background-color: var(--primary);
  color: white;
}

.btn-primary:hover {
  background-color: var(--primary-hover);
}

.btn-secondary {
  background-color: var(--primary-light);
  color: var(--primary);
}

.btn-secondary:hover {
  background-color: #c7d2fe;
}

.btn-danger {
  background-color: #fee2e2;
  color: var(--danger);
}

.btn-danger:hover {
  background-color: #fecaca;
}

.btn-icon {
  padding: 6px;
  border-radius: 50%;
  background-color: var(--bg-primary);
  color: var(--text-secondary);
  border: 1px solid var(--border);
}

.btn-icon:hover {
  background-color: var(--border);
  color: var(--text-primary);
}

/* Cart Section */
.cart-section {
  background-color: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 24px;
  box-shadow: var(--shadow-sm);
  align-self: start;
  position: sticky;
  top: 90px;
}

.cart-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-bottom: 1px solid var(--border);
  padding-bottom: 16px;
  margin-bottom: 16px;
}

.cart-title {
  font-size: 18px;
  font-weight: 700;
  margin: 0;
  display: flex;
  align-items: center;
  gap: 8px;
}

.cart-badge {
  background-color: var(--primary);
  color: white;
  font-size: 12px;
  font-weight: 700;
  padding: 2px 8px;
  border-radius: 20px;
}

.cart-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 40px 0;
  color: var(--text-secondary);
  text-align: center;
  gap: 12px;
}

.cart-empty-icon {
  color: var(--text-muted);
  width: 48px;
  height: 48px;
}

.cart-items-list {
  display: flex;
  flex-direction: column;
  gap: 16px;
  max-height: 350px;
  overflow-y: auto;
  padding-right: 4px;
  margin-bottom: 20px;
}

/* Custom scrollbar for cart list */
.cart-items-list::-webkit-scrollbar {
  width: 6px;
}
.cart-items-list::-webkit-scrollbar-track {
  background: var(--bg-primary);
  border-radius: 3px;
}
.cart-items-list::-webkit-scrollbar-thumb {
  background: var(--text-muted);
  border-radius: 3px;
}

.cart-item {
  display: flex;
  gap: 12px;
  align-items: center;
  padding-bottom: 16px;
  border-bottom: 1px solid #f1f5f9;
}

.cart-item-image {
  width: 50px;
  height: 50px;
  object-fit: cover;
  border-radius: var(--radius-sm);
  background-color: #f1f5f9;
}

.cart-item-details {
  flex-grow: 1;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.cart-item-name {
  font-size: 14px;
  font-weight: 600;
  margin: 0;
  color: var(--text-primary);
  display: -webkit-box;
  -webkit-line-clamp: 1;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.cart-item-price {
  font-size: 13px;
  color: var(--primary);
  font-weight: 600;
}

.cart-item-controls {
  display: flex;
  align-items: center;
  gap: 8px;
}

.quantity-display {
  font-size: 14px;
  font-weight: 700;
  min-width: 20px;
  text-align: center;
}

.cart-summary {
  border-top: 1px solid var(--border);
  padding-top: 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.summary-row {
  display: flex;
  justify-content: space-between;
  font-size: 14px;
  color: var(--text-secondary);
}

.summary-total {
  font-size: 18px;
  font-weight: 800;
  color: var(--text-primary);
  border-top: 1px dashed var(--border);
  padding-top: 12px;
  margin-top: 4px;
}

.checkout-btn {
  width: 100%;
  margin-top: 8px;
}

/* Loading & Error States */
.loading-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 60px 0;
  color: var(--text-secondary);
  gap: 16px;
}

.spinner {
  border: 4px solid rgba(79, 70, 229, 0.1);
  width: 40px;
  height: 40px;
  border-radius: 50%;
  border-left-color: var(--primary);
  animation: spin 1s linear infinite;
}

@keyframes spin {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

.error-container {
  background-color: #fef2f2;
  border: 1px solid #fee2e2;
  border-radius: var(--radius);
  padding: 24px;
  color: var(--danger);
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
}

/* Utilities */
.text-center {
  text-align: center;
}

.footer {
  margin-top: auto;
  background-color: var(--bg-card);
  border-top: 1px solid var(--border);
  padding: 24px;
  color: var(--text-secondary);
  font-size: 14px;
}

import {
  createRootRoute,
  createRoute,
  createRouter,
  RouterProvider,
  useNavigate,
  useSearch,
  Outlet,
} from '@tanstack/react-router';
import { useQuery } from '@tanstack/react-query';
import { fetchProducts, Product } from './api';
import {
  ShoppingBag,
  ShoppingCart,
  Trash2,
  Plus,
  Minus,
  AlertTriangle,
  Sparkles,
  Check,
} from 'lucide-react';
import { useState } from 'react';

// Define structures
interface CartItem {
  id: number;
  quantity: number;
}

interface CartSearch {
  cart?: CartItem[];
}

// Root Route
const rootRoute = createRootRoute({
  component: () => (
    <div id="root">
      <header className="header">
        <div className="header-content">
          <a href="/" className="logo">
            <ShoppingBag className="logo-icon" />
            <span>TanShop</span>
          </a>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '14px', color: 'var(--text-secondary)' }}>
            <span style={{ display: 'inline-block', width: '8px', height: '8px', borderRadius: '50%', backgroundColor: '#22c55e' }}></span>
            <span>TanStack Powered</span>
          </div>
        </div>
      </header>
      <main style={{ flexGrow: 1 }}>
        <Outlet />
      </main>
      <footer className="footer">
        <div className="app-container text-center">
          <p>© {new Date().getFullYear()} TanShop. Built with TanStack Query & TanStack Router.</p>
        </div>
      </footer>
    </div>
  ),
});

// Index Component (Main shopping page)
function IndexComponent() {
  const search = useSearch({ from: '/' }) as CartSearch;
  const navigate = useNavigate({ from: '/' });
  const [checkoutSuccess, setCheckoutSuccess] = useState(false);

  // TanStack Query for products
  const { data: products, isLoading, error } = useQuery<Product[]>({
    queryKey: ['products'],
    queryFn: fetchProducts,
  });

  const cart = search.cart || [];

  // Helper to update the cart search parameter
  const updateCart = (newCart: CartItem[]) => {
    setCheckoutSuccess(false); // Reset checkout success state on cart interaction
    navigate({
      search: (prev) => ({
        ...prev,
        cart: newCart.length > 0 ? newCart : undefined, // clean up empty cart from URL
      }),
    });
  };

  // Add item to cart
  const handleAddToCart = (productId: number) => {
    const existingIndex = cart.findIndex((item) => item.id === productId);
    if (existingIndex > -1) {
      const newCart = [...cart];
      newCart[existingIndex] = {
        ...newCart[existingIndex],
        quantity: newCart[existingIndex].quantity + 1,
      };
      updateCart(newCart);
    } else {
      updateCart([...cart, { id: productId, quantity: 1 }]);
    }
  };

  // Update item quantity
  const handleUpdateQuantity = (productId: number, delta: number) => {
    const existingIndex = cart.findIndex((item) => item.id === productId);
    if (existingIndex > -1) {
      const newCart = [...cart];
      const newQuantity = newCart[existingIndex].quantity + delta;
      if (newQuantity <= 0) {
        // Remove item if quantity goes to 0 or less
        newCart.splice(existingIndex, 1);
      } else {
        newCart[existingIndex] = {
          ...newCart[existingIndex],
          quantity: newQuantity,
        };
      }
      updateCart(newCart);
    }
  };

  // Remove item from cart
  const handleRemoveFromCart = (productId: number) => {
    const newCart = cart.filter((item) => item.id !== productId);
    updateCart(newCart);
  };

  // Clear cart
  const handleClearCart = () => {
    updateCart([]);
  };

  // Calculate cart details
  const cartItemsDetails = cart
    .map((item) => {
      const product = products?.find((p) => p.id === item.id);
      if (!product) return null;
      return {
        product,
        quantity: item.quantity,
        subtotal: product.price * item.quantity,
      };
    })
    .filter((item): item is { product: Product; quantity: number; subtotal: number } => item !== null);

  const totalItemsCount = cart.reduce((acc, item) => acc + item.quantity, 0);
  const totalPrice = cartItemsDetails.reduce((acc, item) => acc + item.subtotal, 0);

  const handleCheckout = () => {
    setCheckoutSuccess(true);
    updateCart([]); // Clear cart in URL
  };

  return (
    <div className="app-container">
      <div className="main-layout">
        {/* Products Section */}
        <div className="products-section">
          <h2 className="section-title">
            <Sparkles size={20} style={{ color: 'var(--primary)' }} />
            <span>Our Products</span>
          </h2>

          {isLoading && (
            <div className="loading-container">
              <div className="spinner"></div>
              <p>Fetching amazing products for you...</p>
            </div>
          )}

          {error && (
            <div className="error-container">
              <AlertTriangle size={40} />
              <h3>Failed to load products</h3>
              <p>{(error as Error).message || "An unexpected error occurred."}</p>
            </div>
          )}

          {products && (
            <div className="products-grid">
              {products.map((product) => {
                const cartItem = cart.find((item) => item.id === product.id);
                return (
                  <div className="product-card" key={product.id}>
                    <div className="product-image-container">
                      <img
                        src={product.image}
                        alt={product.name}
                        className="product-image"
                        loading="lazy"
                      />
                      <span className="product-category">{product.category}</span>
                    </div>
                    <div className="product-info">
                      <h3 className="product-name">{product.name}</h3>
                      <p className="product-desc">{product.description}</p>
                      <div className="product-footer">
                        <span className="product-price">${product.price.toFixed(2)}</span>
                        <button
                          className={`btn ${cartItem ? 'btn-secondary' : 'btn-primary'}`}
                          onClick={() => handleAddToCart(product.id)}
                        >
                          {cartItem ? (
                            <>
                              <Check size={16} />
                              <span>In Cart ({cartItem.quantity})</span>
                            </>
                          ) : (
                            <>
                              <ShoppingCart size={16} />
                              <span>Add to Cart</span>
                            </>
                          )}
                        </button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Cart Section */}
        <div className="cart-section">
          <div className="cart-header">
            <h3 className="cart-title">
              <ShoppingCart size={20} />
              <span>Shopping Cart</span>
            </h3>
            {totalItemsCount > 0 && (
              <span className="cart-badge">{totalItemsCount} {totalItemsCount === 1 ? 'item' : 'items'}</span>
            )}
          </div>

          {checkoutSuccess && (
            <div style={{
              backgroundColor: '#f0fdf4',
              border: '1px solid #bbf7d0',
              borderRadius: 'var(--radius-sm)',
              padding: '16px',
              color: '#15803d',
              textAlign: 'center',
              marginBottom: '16px',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
