              border: '1px solid #bbf7d0',
              borderRadius: 'var(--radius-sm)',
              padding: '16px',
              color: '#15803d',
              textAlign: 'center',
              marginBottom: '16px',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: '8px'
            }}>
              <Check size={24} style={{ color: '#16a34a' }} />
              <h4 style={{ margin: 0, fontWeight: 700 }}>Order Placed!</h4>
              <p style={{ margin: 0, fontSize: '13px' }}>Thank you for your purchase. Your cart has been cleared.</p>
            </div>
          )}

          {cartItemsDetails.length === 0 ? (
            <div className="cart-empty">
              <ShoppingBag className="cart-empty-icon" />
              <p style={{ fontWeight: 600, margin: 0 }}>Your cart is empty</p>
              <p style={{ fontSize: '13px', margin: 0 }}>Add products from the left to start shopping!</p>
            </div>
          ) : (
            <>
              <div className="cart-items-list">
                {cartItemsDetails.map(({ product, quantity, subtotal }) => (
                  <div className="cart-item" key={product.id}>
                    <img src={product.image} alt={product.name} className="cart-item-image" />
                    <div className="cart-item-details">
                      <h4 className="cart-item-name">{product.name}</h4>
                      <div className="cart-item-price">
                        ${product.price.toFixed(2)} x {quantity}
                      </div>
                    </div>
                    <div className="cart-item-controls">
                      <button
                        className="btn-icon"
                        onClick={() => handleUpdateQuantity(product.id, -1)}
                        aria-label="Decrease quantity"
                      >
                        <Minus size={12} />
                      </button>
                      <span className="quantity-display">{quantity}</span>
                      <button
                        className="btn-icon"
                        onClick={() => handleUpdateQuantity(product.id, 1)}
                        aria-label="Increase quantity"
                      >
                        <Plus size={12} />
                      </button>
                      <button
                        className="btn-icon"
                        style={{ color: 'var(--danger)', marginLeft: '4px' }}
                        onClick={() => handleRemoveFromCart(product.id)}
                        aria-label="Remove item"
                      >
                        <Trash2 size={12} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              <div className="cart-summary">
                <div className="summary-row">
                  <span>Subtotal</span>
                  <span>${totalPrice.toFixed(2)}</span>
                </div>
                <div className="summary-row">
                  <span>Shipping</span>
                  <span style={{ color: '#16a34a', fontWeight: 600 }}>FREE</span>
                </div>
                <div className="summary-row summary-total">
                  <span>Total</span>
                  <span>${totalPrice.toFixed(2)}</span>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginTop: '12px' }}>
                  <button className="btn btn-danger" onClick={handleClearCart}>
                    <Trash2 size={16} />
                    <span>Clear</span>
                  </button>
                  <button className="btn btn-primary" onClick={handleCheckout}>
                    <span>Checkout</span>
                  </button>
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

